sys_script_client.script:
function onLoad() {
   //Type appropriate comment here, and begin script below

    var fields = [
        'access_level',
        'device_type',
        'device_name',
        'start_date',
        'end_date',
        'ip_address',
        'port_number',
        'website_url',
        'building',
        'floor',
        'desk_number',
        'issue_description'
    ];

    for (var i = 0; i < fields.length; i++) {
        g_form.setDisplay(fields[i], false);
    }

    var requestType = g_form.getValue('request_type');

    if (requestType) {
        g_form.setValue('request_type', requestType);
        g_form.flash('request_type');
    }
}
